import { TabEventClient } from "../CachedTabs";

export const useTabs = () => {
    /**
     * 关闭当前Tab
     */
    const close = (autoRedirect: boolean = false) => {
        TabEventClient.closeCurrent(autoRedirect);
    }

    /**
     * 通过Key关闭Tab
     * @param args 
     */
    const closeByKey = (key: string, autoRedirect: boolean = false) => {
        TabEventClient.close(key, autoRedirect);
    }

    /**
     * 通过当前路由的pathname关闭Tab
     * @param args 
     */
    const closeByPathname = (pathname: string, autoRedirect: boolean = false) => {
        TabEventClient.closeByPathname(pathname, autoRedirect);
    }

    /**
     * 关闭其他Tab
     * @param args 
     */
    const closeOther = (key: string) => {
        TabEventClient.closeOther(key);
    }

    /**
     * 刷新Tab
     * @param args 
     */
    const refresh = (...args: Parameters<typeof TabEventClient.refresh>) => {
        TabEventClient.refresh(...args);
    }

    /**
     * 
     * 更新Tab
     * @param args 
     */
    const update = (...args: Parameters<typeof TabEventClient.update>) => {
        TabEventClient.update(...args);
    }

    /**
     * 固定Tab，不可关闭，刷新保留
     * @param args 
     */
    const sticky = (...args: Parameters<typeof TabEventClient.sticky>) => {
        TabEventClient.sticky(...args);
    }

    const unSticky = (...args: Parameters<typeof TabEventClient.unSticky>) => {
        TabEventClient.unSticky(...args);
    }

    return {
        close,
        closeByKey,
        closeByPathname,
        closeOther,
        refresh,
        update,
        sticky,
        unSticky,
    }
}